var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"소문으로만 듣던 전쟁영웅을 뵙게 되어 영광입니다.","JPN":"噂で聞いていた戦争英雄にお会いできて光栄です。","ENG":"It is an honor to finally meet the war hero I had only heard of in rumors.","TWN":"能見到傳說中的戰爭英雄是我的榮幸。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"……마리아 안토노프 중장.","JPN":"……マリア・アントノフ中将。","ENG":"...Lieutenant General Maria Antonov.","TWN":"……瑪麗亞·安東諾夫中將。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"영웅이라니 낯간지럽군. 지금은 퇴역을 앞둔 늙은이일 뿐이네.","JPN":"英雄とは大袈裟だな。今の私は退役を控えた老人にすぎない。","ENG":"\\"Hero,\\" you say? That's flattering. I'm just an old soldier about to retire.","TWN":"居然說我是英雄，真是難為情，我現在只不過是個即將退役的老人。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이런 외지, 그것도 북방합의체의 총참모장에게 영웅 취급을 받을 줄은 몰랐군.","JPN":"よその地で……それも北方合意体の総参謀長に英雄と呼ばれるとはな。","ENG":"I did not expect to be treated like a hero out here, much less by the Northern Union's Chief of the General Staff.","TWN":"沒想到會在這樣的外地，還被北方和議會總參謀長當成英雄。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"비록 망명했다지만 안토노프 중장의 조부께서는 러시아 출신일뿐더러…….","JPN":"亡命したとはいえ、アントノフ中将のお祖父様はロシア出身ですし……","ENG":"Though he went into exile, your grandfather was Russian...","TWN":"雖然已經逃亡，但安東諾夫中將的祖父不僅來自俄羅斯……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"안토노프 중장께서는 대정화전쟁을 승리로 이끈 주역들 중 한 분이니까요.","JPN":"それに中将ご自身は、大浄化戦争を勝利に導いた主役の一人ですから。","ENG":"And you, Lieutenant General Antonov, were one of the key figures who led the Grand Purification War to victory.","TWN":"而且安東諾夫中將還是引領大淨化戰爭走向勝利的主角之一。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"당신이 없었다면 시베리아 일대는 차가운 얼음고원에 불과할 테니, 구국의 영웅으로 모시는 건 당연합니다.","JPN":"あなたがいなければシベリア一帯は凍りついた高原にすぎませんでした。救国の英雄として称えるのは当然のことです。","ENG":"Without you, all Siberia would be nothing but a frozen plateau. Honoring you as a hero is only proper.","TWN":"要不是妳的話，西伯利亞一帶只不過是冰冷的冰原，當然要把妳奉為救國英雄。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"제가 실례되는 말이라도 했을까요?","JPN":"私が何か失礼なことでも？","ENG":"Did I say something out of line?","TWN":"我說了什麼失禮的話嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"전혀. 상상한 것과 이미지가 달라 놀랐을 뿐이네.","JPN":"いや。想像していたのと印象が違って驚いただけだ。","ENG":"Not at all. I am just surprised you are not what I pictured.","TWN":"沒有，只是妳和我想像中的形象不一樣，覺得驚訝而已。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"합의체의 총참모장은 사적 제재를 일삼는 살인마라는 소문을 들어 제법 거친 대화가 되지 않을까 우려했거든.","JPN":"噂では、合意体の総参謀長は私的制裁に明け暮れる殺人鬼と聞いていたものでね。荒っぽい対話になるのではないかと心配していたんだ。","ENG":"Word was the Northern Union's Chief of the General Staff is a butcher who hands out extrajudicial punishments, so I braced for a rough exchange.","TWN":"我聽說和議會的總參謀長是專門動用私刑的殺人魔，所以本來擔心對話會不會很粗暴。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"소문이 사실일 수도 있겠죠.","JPN":"噂が事実かもしれませんよ。","ENG":"The rumors may well be true.","TWN":"傳聞也可能是真的。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇겠지.","JPN":"だろうな。","ENG":"Perhaps.","TWN":"應該是吧。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 개인의 소견을 밝히자면, 자네 같은 사람은 대개 철두철미하게 움직인다네.","JPN":"だが、個人的な意見を述べると、君のような人は徹底的に計算で動く。","ENG":"Speaking personally, people like you usually operate with meticulous care.","TWN":"但如果要說我個人的看法，像妳這樣的人通常都是徹頭徹尾地行動。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"살인이면 흔적을, 사적 제재라면 소문을 숨기고…….","JPN":"殺人に対しては痕跡を消し、私的制裁に対しては噂をもみ消す……","ENG":"If you kill, you erase the traces. If you punish off the books, you bury the rumors...","TWN":"殺人的話會不留痕跡，動用私刑的話會掩蓋傳聞……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"군인을 상대로는 예의보다 총칼을 갖췄겠지.","JPN":"軍人相手には礼儀より銃と剣を用意したはずだ。","ENG":"And against soldiers, you would bring steel before courtesy.","TWN":"面對軍人，比起禮儀，更應該具備刀槍吧。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"호위 없이 오라는 말이 예의를 갖췄다고 생각되지는 않네요.","JPN":"護衛を付けずに来てほしいという言葉が、礼儀を重んじたものだとは思いませんが。","ENG":"Asking me to come without an escort hardly strikes me as courteous.","TWN":"在沒有護衛的情況下要妳來，我認為這不符合禮儀。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"중장께서 계신 곳은 다름아닌 북방합의체 영토권이니까요.","JPN":"中将がいるこの場所は北方合意体の領土圏内ですから。","ENG":"Especially when you are standing in the Northern Union territory.","TWN":"因為中將所在之處不是其他地方，而是北方和議會的領土圈。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"인질이 필요하다면 내가 아니라 다른 쪽을 노렸겠지.","JPN":"人質が必要なら私ではなく、他を狙っただろう。","ENG":"If you needed a hostage, you would have targeted someone else, not me.","TWN":"如果需要人質，目標應該不是我，而是其他人吧。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네가 나를 독대할 이유는 더더욱 없고.","JPN":"君が私と会談の場を持つべき理由は尚更ない。","ENG":"You have even less reason to meet me alone.","TWN":"而且妳更沒有要單獨接見我的理由。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"쉽지 않은 협상이 될 줄 알았는데 다행이야.","JPN":"難しい交渉になると思ったが、よかったよ。","ENG":"I expected hardball, so this is a relief.","TWN":"我還以為會是場不容易的協商，但真是萬幸。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"우리 쪽에도 협상테이블에 앉을만한 판돈은 있는 모양이군.","JPN":"どうやら我々にも、テーブルにつけるだけのカードはあるようだ。","ENG":"Sounds like we brought enough chips to sit at the table.","TWN":"看來我們這邊也有能坐上談判桌的賭注。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"...Haha.","TWN":"……呵呵。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"이럴 줄 알았다면 조금 강압적인 태도를 취할 걸 그랬네요.","JPN":"こうなると分かっていたら、もう少し高圧的な態度を取るべきでしたね。","ENG":"If I had known, I might have taken a more coercive stance.","TWN":"早知道這樣，我就應該採取稍微強制的態度。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"귀한 차를 내준 건 고맙지만, 티타임보다 서로의 입장을 명확하게 밝히는 게 좋겠군.","JPN":"貴重なお茶を出してくれたことには感謝するが、ティータイムよりは互いの立場を明確にするほうが先だな。","ENG":"I appreciate the fine tea, but let's make our positions clear rather than linger on tea time.","TWN":"雖然很感謝妳端出貴重的茶，但比起喝茶時間，還是表明彼此的立場比較好。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"합중국은 관리국의 지원 요청을 받았네.","JPN":"合衆国は管理局の支援要請を受けた。","ENG":"The States received a request for support from the Administration.","TWN":"合眾國接獲了管理局的支援請求。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"공식적인 절차는 아니지만, 시니어 코드를 소지한 공인 카운터의 요청이었지.","JPN":"公式的な手続きではないが、シニアコードを所持した公認カウンターからの要請だった。","ENG":"Although it was not through official channels, the request came from an Official Counter holding a Senior Code.","TWN":"雖然不是正式程序，但這是持有Senior代碼的公認制裁者提出的請求。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그 과정에 북방합의체의 개입이 있었나?","JPN":"その過程に北方合意体の介入はあったのか？","ENG":"Was the Northern Union involved in that process?","TWN":"北方和議會在這過程中有介入嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그렇게 생각하신 이유가 있나요?","JPN":"そうお考えになった理由は何ですか？","ENG":"Do you have a reason to think so?","TWN":"妳為什麼會這麼想？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"관리국 쪽에서 합의체와의 협력이 불가피하다고 말한 것.","JPN":"管理局側から、合意体との協力が必要不可欠だと言い出したこと。","ENG":"The Administration said cooperation with the Northern Union was unavoidable.","TWN":"管理局方面說過與和議會合作是在所難免的。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 그 과정에서 합중국의 손님을 맞이하기 위해 자네가 직접 모습을 드러낸 것.","JPN":"その過程で合衆国からの客を迎えるために、君自らが姿を現したこと。","ENG":"Then you personally showed up to receive guests from the States.","TWN":"而且在這過程中，妳還親自露面迎接合眾國的客人。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이 일련의 과정이 단순 우연이라고 생각되지는 않는군.","JPN":"この一連の流れが、ただの偶然とは思えない。","ENG":"I doubt that string of events is mere coincidence.","TWN":"我不認為這一連串的過程是單純巧合。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"반박하지 않는 건가?","JPN":"反論しないのか？","ENG":"No rebuttal?","TWN":"妳不反駁嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"전 시간낭비를 싫어하거든요.","JPN":"時間を無駄にすることが嫌いなんです。","ENG":"I dislike wasting time.","TWN":"我不喜歡浪費時間。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"속여넘길 수 없는 상대에게 구태여 거짓을 늘여놓을 필요는 없죠.","JPN":"騙せない相手にわざわざ嘘を並べる必要はありません。","ENG":"There is no need to spin lies for someone I cannot fool.","TWN":"在瞞不過的對象面前沒必要非得謊話連篇。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"예상하신 게 맞아요. 저는 시니어 잭슨으로부터 코드를 넘겨받은 뒤.","JPN":"その通りです。私はシニア・ジャクソンからコードを渡され……","ENG":"You guessed right. After receiving the code from Senior Jackson,","TWN":"妳的預想沒錯，我從Senior傑森那裡拿到代碼後，"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"챔버의 공인 카운터가 그걸 사용할 수밖에 없는 상황을 조성했어요.","JPN":"チェンバーの公認カウンターがそれを使うしかない状況を作りました。","ENG":"I engineered circumstances that forced Chamber's Official Counter to use it.","TWN":"就形成了密室公認制裁者不得不使用的情況。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"설마, 시니어 잭슨이 북방합의체와 공모하고 있었다는 뜻인가?","JPN":"まさか、シニア・ジャクソンが北方合意体と共謀していたということか？","ENG":"Are you implying Senior Jackson was colluding with the Northern Union?","TWN":"難道妳的意思是Senior傑森和北方和議會串通嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"지금 중요한 내용은 아닌 것 같네요.","JPN":"その点に関しましては、今はさほど重要ではないかと。","ENG":"That does not seem relevant right now.","TWN":"這好像不是現在重要的內容。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"제가 제공해드릴 수 있는 정보는 오롯이 중장님께서 움직인 건에 관해서예요.","JPN":"私が提供できる情報は、中将が動いた件についてだけです。","ENG":"The information I can provide concerns the operation you, personally, set in motion.","TWN":"我能提供的就只有關於中將行動的情報。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 굳이 불필요한 사족을 달 필요는 없겠지.","JPN":"ああ、確かに不要な情報は要らないな。","ENG":"Fair enough. No need for extraneous tangents.","TWN":"沒錯，應該沒必要硬是畫蛇添足。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"시니어 코드에 대해 알고 있다면, 합중국의 개입 또한 자네가 유도한 건가?","JPN":"シニアコードについて知っているということは、合衆国の介入も君が誘導したのか？","ENG":"If you know about the Senior Code, then did you also steer the States' involvement?","TWN":"既然知道關於Senior代碼的事，難道合眾國的介入也是妳誘導的嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"어느정도는 유도했다고 볼 수 있겠네요.","JPN":"ある程度はそうと言えますね。","ENG":"You could say I nudged it along to a certain degree.","TWN":"某種程度應該能看作是誘導。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇다면 그건 얼마 뒤 벌어질 전세계적인 대균열 이상 현상 때문이겠군.","JPN":"だとすると、まもなく全世界で起こるはずの、大亀裂異常現象と関係があるんだろう。","ENG":"Then this is about the worldwide Grand Dimension Crevice anomalies about to break out.","TWN":"那麼應該是因為不久後將發生的全世界大峽谷異常現象。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"북방합의체 영토권에는 그라운드 제로라는 대균열이 존재하니.","JPN":"北方合意体の領土圏内にはグラウンド・ゼロという大亀裂が存在しているからな。","ENG":"The Northern Union territory holds a Grand Dimension Crevice called Ground Zero.","TWN":"北方和議會領土圈有個叫Ground Zero的大峽谷。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이곳에 온 시점에서 우린 합의체에 협력할 수밖에 없겠지.","JPN":"ここに来た時点で、我々は合意体に協力するしかない。","ENG":"Once we came here, we had little choice but to work with the Northern Union.","TWN":"來到這裡的時候應該就只能配合我們和議會了。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"흐음-.","JPN":"ふむ。","ENG":"Hmm.","TWN":"嗯哼–"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"아쉽네요. 소속이 같았다면 제 주도하에 중장님을 북방합의체의 수장으로 모셨을 텐데.","JPN":"残念ですね。所属が同じだったら私が主導して中将を北方合意体の長としてお迎えしたのに。","ENG":"A shame. If we wore the same colors, I would have installed you as head of the Northern Union under my lead.","TWN":"真可惜，要是我們隸屬同個地方，應該就會在我的主導下請妳擔任北方和議會的首領。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"누가 할 소리. 자네가 군인이었다면 내 후임으로 점찍어뒀을 걸세.","JPN":"こちらのセリフさ。君が軍人だったら、私の後任として目をつけていた。","ENG":"Look who's talking. If you were in the military, I would have marked you as my successor.","TWN":"這應該是我要說的話， 如果你是軍人，我早就相中你當我的繼任者了。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그렇다면, 일시협력 관계라고 생각해도 좋은 걸까요?","JPN":"でしたら、一時的な協力関係になった、と思ってもいいのでしょうか。","ENG":"In that case, may I consider this a temporary partnership?","TWN":"這樣的話，可以想成是暫時合作關係嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네 말이 맞군. 뜨겁게 우려내서 그런지 딱 좋게 식었어.","JPN":"君の言った通りだ。熱く淹れたからか、ちょうどいい温度さ。","ENG":"You are right. The tea is just right now that it has cooled a touch.","TWN":"妳說得對，可能是因為泡出來熱騰騰，這樣涼得剛剛好。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"익숙하지 않은 향인데, 어떤 차인지 알려주겠나?","JPN":"嗅いだことのない香りだが、どういうお茶なのかな？","ENG":"The aroma is unfamiliar. What blend is it?","TWN":"雖然是不熟悉的香味，但能告訴我是什麼茶嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"이곳에서 자라는 꽃으로 우려낸 차예요. 향이 좋아서 집중이 필요할 때 애용하죠.","JPN":"ここで育つ花で淹れたお茶です。香りがいいので、集中したい時よく飲みます。","ENG":"A tea brewed from local flowers. The fragrance is pleasant, so I use it when I need to focus.","TWN":"是用在這裡生長的花朵泡的茶，因為味道很香，需要專注的時候經常飲用。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"원한다면 조금 나눠드릴까요?","JPN":"よろしければ少しお分けしましょうか。","ENG":"Would you like some to take with you?","TWN":"想要的話，要不要分妳一點？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 일을 끝마친 뒤에 대원들과 티타임이라도 벌여야겠어.","JPN":"ああ、仕事が終わったら隊員のみんなとティータイムでも楽しむとしよう。","ENG":"Yes. After this, I should host a little tea time with my unit.","TWN":"好，等工作結束後，應該要和隊員們來個喝茶時間。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이제 자네의 계획을 설명해줬으면 좋겠군.","JPN":"では、君の計画を説明してくれ。","ENG":"Now, tell me your plan.","TWN":"現在希望妳能說明一下自己的計畫。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"합중국과 관리국에 손을 뻗은 만큼, 마땅한 계획이 있겠지?","JPN":"合衆国と管理局にまで手を広げたということは、それなりの計画は立てているんだろう？","ENG":"If you reached out to the States and the Administration, you had better have one.","TWN":"妳已經伸手觸及合眾國和管理局，應該有適當的計畫吧？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"힉스로부터 대략적인 정보는 들으셨을 테니, 우선 대균열에서 뻗어 나오는 뿌리의 근원을 설명해야겠네요.","JPN":"ヒックスから大まかな情報は聞いていると思いますが、まずは大亀裂から伸びてくる根の根源から説明しましょう。","ENG":"You heard the broad strokes from Hicks, so I should start with the source of the roots that branch out from the Grand Dimension Crevices.","TWN":"妳應該從希格斯那裡聽過大概的情報，首先要說明從大峽谷延伸出的根部根源。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"중장님은 요정에 대해 알고 계신가요?","JPN":"中将は妖精についてご存知ですか？","ENG":"Are you familiar with fairies?","TWN":"中將知道關於精靈的事嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"요정…?","JPN":"妖精……？","ENG":"Fairies...?","TWN":"精靈…？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"요정이란 노르드나빅의 전승 속 존재…….","JPN":"妖精はノルドナビックの伝承に出てくる存在……","ENG":"In Nordnavik lore, fairies are beings who coexisted with humans.","TWN":"精靈是諾爾德萊比傳承中的存在……"},"stage":{"bg":"EV_SIGMA_01","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"인간과 공생하기 위해 어떤 나무의 가능성을 양분으로 삼은 자들을 일컫죠.","JPN":"人間と共生するために、とある木の可能性を養分とした者たちを指します。","ENG":"They took the possibilities of a certain tree as their nourishment to live alongside us.","TWN":"為了與人類共生，把某種樹的可能性當成養分的人。"},"stage":{"bg":"EV_SIGMA_01","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그리고 요정이 양분으로 삼는 나무의 이름이 바로, 황금나무.","JPN":"そして妖精が養分とする木の名前は、黄金の木。","ENG":"That tree was called the Golden Tree.","TWN":"而精靈ˊ當成養分的樹，名字就叫黃金樹。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"아발론이라는 옛 왕국의 역병을 몰아낸 무구한 가능성을 지닌 세계수입니다.","JPN":"アバロンという昔の王国で疫病を追い払った、無限の可能性を持つ世界樹です。","ENG":"It is the World Tree of Avalon, the fallen kingdom, bearing unsullied possibilities that drove out the plague.","TWN":"這是具有驅逐阿瓦隆這個舊王國瘟疫之純淨可能性的世界樹。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"설마, 전승 속 나무가 대균열로부터 뻗어 나오는 뿌리의 근원이라 말할 셈인가?","JPN":"まさか、伝承に出てくる木が大亀裂から伸びる根の根源だと言いたいのか？","ENG":"Do not tell me that some tree from a legend is the source of the roots extending from the Grand Dimension Crevices.","TWN":"難道傳承中的樹木是從大峽谷延伸出的根部之源嗎？"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"전승은 실화로부터 비롯되죠. 노르드나빅의 건 또한 마찬가지예요.","JPN":"伝承は実話から生まれるもの。ノルドナビックの件も同じです。","ENG":"Legends spring from truth. Nordnavik is no exception.","TWN":"傳承源自於真實故事，諾爾德萊比也是一樣。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"요정과 황금나무. 그 모든 것을 품었던 멸망한 세계 엘리시온.","JPN":"妖精と黄金の木。そのすべてを内包していた、今は滅びた世界エリシオン。","ENG":"Fairies and the Golden Tree, and the perished world that held them all... Elysion.","TWN":"精靈和黃金樹，具有這一切的滅亡世界艾利森。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그곳에서 비롯된 황금나무가 뿌리를 통해 멸망한 세계의 공백을 메우려 하는 현상.","JPN":"そこから来た黄金の木が根を通して滅びた世界の空白を埋めようとする現象。","ENG":"The Golden Tree from there is trying to fill that fallen world's void through its roots.","TWN":"源自那裡的黃金樹想透過根部填補滅亡世界空白的現象。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그것이 우리가 맞닥뜨리게 될 전조입니다.","JPN":"それが私たちが直面する前兆の正体です。","ENG":"That is the omen we are about to face.","TWN":"那就是我們將面臨的前兆。"},"stage":{"bg":"ROOT_VILLAGE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"잃어버린 세계의 공백을 메운다니… 뿌리가 새로운 세계를 창조하기라도 한다는 건가?","JPN":"失われた世界の空白を埋めるだなんて……根が新しい世界を作るとでも言いたいのか？","ENG":"Filling a lost world's void... Are those roots trying to create a new world?","TWN":"居然要填補失去的世界空白…難道根部會創造新世界嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"아직 확신할 수 없어요.","JPN":"まだ断言はできません。","ENG":"I cannot say for certain yet.","TWN":"這還無法確定。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"하지만 황금나무가 마왕 타기리온의 근원이 되는 세계로부터 비롯된 것이라면…….","JPN":"しかし黄金の木が、魔王タギリオンの根源となる世界から来たものだとしたら……","ENG":"But if the Golden Tree stems from the world that births the Demon Lord Thagirion...","TWN":"但要是黃金樹源自於魔王塔基里翁根源的世界……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"과연, 이번 클리포트 게임의 상대는 타기리온이라는 마왕이겠군.","JPN":"なるほど、今回のクリフォトゲームの相手はタギリオンという魔王になるな。","ENG":"Then our opponent in this Qliphoth Game is the Demon Lord called Thagirion.","TWN":"果然，這次逆卡巴拉遊戲的對手應該是叫塔基里翁的魔王。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"예상은 했지만, 제법 어려운 전투가 되겠어.","JPN":"予想はしていたが、手強い戦闘になりそうだ。","ENG":"I expected as much. It will be a hard fight.","TWN":"雖然有料想到，但應該會是場很艱難的戰鬥。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"걱정 마세요. 필요한 준비라면 모두 끝마쳤어요.","JPN":"心配は要りません。必要な準備は全部済ませておきました。","ENG":"Rest assured. All necessary preparations are complete.","TWN":"別擔心，已經做好必要準備。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"마침, 다른 이<color=#ffd34c>들</color>에게 도움을 요청한 참이고요.","JPN":"ちょうど、他の者<color=#ffd34c>たち</color>に助けを求めているところです。","ENG":"In fact, I have already asked other <color=#ffd34c>parties</color> for help.","TWN":"我正好也請其他<color=#ffd34c>人</color>幫忙了。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"우리 외에 협력을 요청한 집단이 있다는 건가?","JPN":"我々以外の集団にも協力要請を出したのか？","ENG":"Other parties? You requested cooperation from another group as well?","TWN":"除了我們之外還有能請求幫助的團體嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"네, 지금쯤이면…….","JPN":"はい、今頃……","ENG":"Yes. By now...","TWN":"有，現在……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"시린그라드에 도착했겠네요.","JPN":"シリングラードに着いていることでしょう。","ENG":"They should have reached Ciringrad.","TWN":"應該抵達錫林格勒了。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_SA_COMMANDER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"안드레이, 그쪽은 어때?","JPN":"アンドレイ、そっちはどう？","ENG":"Andrei, how's it on your side?","TWN":"安德烈，那邊怎麼樣？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"문제없어. 합의체가 보낸 선발대는 그 두 명이 전부인 모양이야.","JPN":"問題ない。合意体が送った先発隊はその2人だけのようだ。","ENG":"No problem. Looks like those two were the Northern Union's entire advance party.","TWN":"沒問題，和議會派的先遣隊看起來只有兩個人。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L24_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"북방합의체 녀석들. 보나마나 아이들을 내세워 장기말로 쓸 생각이었겠지.","JPN":"北方合意体のやつらめ。目的のためなら、あんな子どもまで利用するのか。","ENG":"Those Northern Union bastards. Figures they would shove kids to the front and use them as pawns.","TWN":"北方和議會那些傢伙，不用看都知道是想用孩子當作象棋。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"인질로 잡은 아이들은 어때? 처우에 관해 뭔가 이야기가 나왔어?","JPN":"人質の子どもたちは？　処遇について何か話した？","ENG":"What about the children we took hostage? Any word on how to treat them?","TWN":"抓來當人質的孩子們如何？有說些什麼關於待遇的事嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"적대적인 태도는 아니니 교섭의 여지가 있어.","JPN":"敵対的な態度ではないから、まだ交渉の余地はある。","ENG":"They aren't acting hostile, so there's room to negotiate.","TWN":"他們沒有展現敵對態度，有交涉的餘地。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"잘 설득한다면, 드레카바크 건에 관한 합의체의 입장을 알 수 있겠지.","JPN":"上手く説得すれば、ドレカバクの件について合意体がどんな立場を取っているかも聞き出せるだろう。","ENG":"If we play our cards right, we might get the Northern Union's stance on the Drekavac matter.","TWN":"要是好好說服的話，應該能知道和議會對於德蕾卡娃克的立場。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"왜 그래? 뭔가 걸리는 점이라도 있어?","JPN":"どうした？　何か引っかかるところでもあるのか？","ENG":"What's wrong? Something bothering you?","TWN":"怎麼了？有什麼掛心的地方嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"미확인 거수자 발견. 대응하며 시간을 끌 테니, 지원 요청바람.","JPN":"挙動不審者を発見。対応しつつ時間を稼ぐ。支援を求む。","ENG":"Unidentified suspicious person spotted. Requesting support while I deal with the matter.","TWN":"發現未確認的可疑人士，我會做出應對拖延時間，請求支援。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"DRAGON_NANAHARA_QM_NULL","text":{"KOREA":"에잉. 생긴 것도 사납게 생겨서는, 지 애비 이름만 아니라 심성까지 물려받았군, 아주.","JPN":"ちっ。凶暴そうだし、名だけじゃなく性格も父から譲り受けたのじゃな。","ENG":"Ugh. Like father like daughter, I suppose. Inheriting not just her father's mean-looking face and name, but even his nasty nature.","TWN":"唉唷，長相凶狠，不只是繼承父親的名字，還繼承了他的心性。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"DRAGON_NANAHARA_QM_NULL","text":{"KOREA":"설명서도 없이 항법 장치만 달랑 보내면, 내가 길을 어떻게 찾으라는 거야?","JPN":"説明書もなく航法装置だけで、どうやってたどり着けというんじゃ。","ENG":"How am I supposed to find this place when she sent me a navigation system but no manual?","TWN":"沒有任何說明書，只送來一台導航裝置，要我怎麼找路？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"정지. 움직이지 마.","JPN":"そこ、止まりなさい。","ENG":"Freeze. Don't move.","TWN":"停止，不要動。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DRAGON_NANAHARA_QM_NULL","text":{"KOREA":"오, 마침 잘 됐군. 안 그래도 길을 잃어 곤란한 참이었거든.","JPN":"お、ちょうどいいところに。道に迷って困っておったのじゃ。","ENG":"Perfect timing. I was lost and in a bind.","TWN":"哦，太好了，我正好也迷路感到不知所措。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DRAGON_NANAHARA_QM_NULL","text":{"KOREA":"이 근처의 시린그라드라는 마을을 찾고 있는데, 혹시 어딘지 아나?","JPN":"この近くの、シリングラードという村を探しておるのじゃが、知らぬか？","ENG":"I am looking for a village called Ciringrad nearby. Do you know where it is?","TWN":"我在找這附近一個叫錫林格勒的村莊，妳知道在哪裡嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"최근 일어난 어수선한 일 때문에 외부인은 받지 않아.","JPN":"最近起こったごたごたのせいで、よそ者は入れないわ。","ENG":"With all the recent turmoil, we are not accepting outsiders.","TWN":"因為最近發生一些亂七八糟的事，他們不接受外部人士來訪。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그러니 이상한 생각 말고 얌전히 돌아가. 괜히 쓴 맛보기 싫다면 말이야.","JPN":"だから余計なことは考えず、大人しく引き返しなさい。痛い目に遭いたくなければね。","ENG":"So drop whatever you are plotting and turn back if you don't want to face pain.","TWN":"所以不要有任何奇怪的念頭，乖乖回去吧，如果不想莫名嚐到苦頭的話。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L43_1","type":"dialog","speaker":"DRAGON_NANAHARA_QM_NULL","text":{"KOREA":"쯧쯔. 어린 것이 대화로 해결할 생각을 해야지. 먼 길 온 손님한테 총부터 들이밀면 쓰나.","JPN":"まったく、最近の若者は……遠路はるばるやってきた客に銃を向けるとはな。会話が先じゃろう？","ENG":"Tsk, tsk. A youngster should try talking first. You do not greet a far-traveled guest by pointing a gun.","TWN":"嘖嘖，小小年紀應該想著用對話來解決事情，怎麼能先對遠道而來的客人用槍？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DRAGON_NANAHARA_QM_NULL","text":{"KOREA":"경계심은 이해하는데, 그리 야박해서야 중요한 걸 놓치는 법이다.","JPN":"警戒する気持ちは分かるが、そうやって薄情にしていると大事なものを見落としてしまうぞ。","ENG":"I get being cautious, but be that stingy and you miss what matters.","TWN":"我理解妳的警戒心，但這麼冷酷無情會錯失重要的東西。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"뭐?","JPN":"何？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"침식체…! 어느 틈에 이렇게 몰려든 거지?","JPN":"侵食体……！　いつの間にこんなに集まってきてたの？","ENG":"C.O.s...! When did this many swarm in?","TWN":"侵蝕體…！什麼時候這樣湧上來了？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DRAGON_NANAHARA_QM_NULL","text":{"KOREA":"흐음. 내가 외부인인 게 문제라면 이건 어떻겠냐?","JPN":"ふむ……よそ者が問題ならこうしたらどうかのう？","ENG":"Hmm. If my being an outsider is the issue, how about this?","TWN":"嗯哼，如果我是外部人士是個問題，那這要怎麼辦？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DRAGON_NANAHARA_QM_NULL","text":{"KOREA":"여기서 널 구해주면, 네가 나를 은인으로서 마을에 안내하는 게다.","JPN":"わしがここでお主を助けてやるから、命の恩人として村に案内するんじゃ。","ENG":"I save you here, and you repay me by escorting your savior into the village.","TWN":"要是我在這裡拯救妳，妳就能把我當作恩人被帶進村子。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"이런 상황에 무슨 농담을…!!","JPN":"こんな状況で冗談を……！！","ENG":"This is no time for jokes...!!","TWN":"在這種情況下開什麼玩笑…！！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"한 방에… 날아갔어? 저 커다란 침식체가?","JPN":"一撃で……吹っ飛んだ？　あの巨大な侵食体が？","ENG":"It got... taken down...? A C.O. that big...?","TWN":"那麼巨大的侵蝕體…一下就不見了？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_45"},{"id":"L7_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……우선.","JPN":"……まずは。","ENG":"...That's one down.","TWN":"……首先，"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L9_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"한 마리.","JPN":"1匹。","ENG":"For now.","TWN":"一隻。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"}]`);export{e as default};